latest_entity_counts.sparql:
SELECT ?graph (COUNT(?aop) AS ?count)
WHERE {
  GRAPH ?graph {
    ?aop a aopo:AdverseOutcomePathway .
  }
}
GROUP BY ?graph
ORDER BY DESC(?graph) LIMIT 1

latest_aop_connectivity.sparql:
SELECT ?graph (COUNT(DISTINCT ?aop1) AS ?connected_aops)
WHERE {
  GRAPH ?graph {
    ?aop1 aopo:has_key_event ?ke .
    ?aop2 aopo:has_key_event ?ke .
    FILTER(?aop1 != ?aop2)
  }
}
GROUP BY ?graph
ORDER BY DESC(?graph) LIMIT 1

latest_database_summary.sparql:
